// Ensure count defaults to 5 and is between 1-5
let count = $json.body.count || 5;
if (!Number.isInteger(count) || count < 1 || count > 5) {
  count = Math.min(5, Math.max(1, parseInt(count) || 5));
}

return {
  count: count,
  platform: $json.body.platform || 'both'
};

