// Extract Claude response from nested structure
const responseContent = $json.content[0].text;

// Parse JSON from Claude
let creatives;
try {
  creatives = JSON.parse(responseContent);
} catch(e) {
  // If Claude wrapped in markdown backticks, extract it
  const jsonMatch = responseContent.match(/```json\n?(.*?)\n?```/s);
  if (jsonMatch) {
    creatives = JSON.parse(jsonMatch[1]);
  } else if (responseContent.match(/^\[/)) {
    // Try raw array
    creatives = JSON.parse(responseContent);
  } else {
    throw new Error('Invalid JSON from Claude: ' + responseContent.substring(0, 200));
  }
}

// Validate it's an array
if (!Array.isArray(creatives)) {
  throw new Error('Response must be an array of creatives');
}

if (creatives.length === 0) {
  throw new Error('No creatives generated');
}

// Validate count matches request
const requestedCount = $items(1)[0].json.count;
if (creatives.length !== requestedCount) {
  console.warn(`Requested ${requestedCount} creatives, got ${creatives.length}`);
}

// Expected labels
const validLabels = ['A', 'B', 'C', 'D', 'E'];

// Validate each creative
for (let i = 0; i < creatives.length; i++) {
  const creative = creatives[i];

  // Check required fields
  const requiredFields = ['split_test_label', 'hook_angle', 'primary_text', 'meta_headline', 'google_headline', 'google_description'];
  for (const field of requiredFields) {
    if (!creative[field]) {
      throw new Error(`Creative ${i + 1} missing field: ${field}`);
    }
  }

  // Validate label
  if (!validLabels.includes(creative.split_test_label)) {
    throw new Error(`Creative ${i + 1} invalid label: ${creative.split_test_label}. Must be A-E.`);
  }

  // Validate character limits
  const primaryLen = creative.primary_text.length;
  if (primaryLen > 125) {
    throw new Error(`Creative ${i + 1} (${creative.split_test_label}) primary_text exceeds 125 chars: ${primaryLen}`);
  }

  const metaHeadlineLen = creative.meta_headline.length;
  if (metaHeadlineLen > 27) {
    throw new Error(`Creative ${i + 1} (${creative.split_test_label}) meta_headline exceeds 27 chars: ${metaHeadlineLen}`);
  }

  const googleHeadlineLen = creative.google_headline.length;
  if (googleHeadlineLen > 30) {
    throw new Error(`Creative ${i + 1} (${creative.split_test_label}) google_headline exceeds 30 chars: ${googleHeadlineLen}`);
  }

  const googleDescLen = creative.google_description.length;
  if (googleDescLen > 90) {
    throw new Error(`Creative ${i + 1} (${creative.split_test_label}) google_description exceeds 90 chars: ${googleDescLen}`);
  }

  // Validate no empty fields
  for (const field of requiredFields) {
    if (creative[field].toString().trim().length === 0) {
      throw new Error(`Creative ${i + 1} (${creative.split_test_label}) ${field} is empty`);
    }
  }

  // Add character counts for UI
  creative.char_counts = {
    primary_text: primaryLen,
    meta_headline: metaHeadlineLen,
    google_headline: googleHeadlineLen,
    google_description: googleDescLen
  };
}

return creatives;
